# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify
import jwt
import requests

app = Flask(__name__)

def validate_token(token):
    try:
        claims = jwt.decode(token, options={"verify_signature": False})
        return claims
    except Exception as e:
        return None

@app.before_request
def authenticate():
    if request.endpoint and request.endpoint != 'health':
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({"error": "Missing or invalid Authorization header"}), 401
        
        token = auth_header.split(' ')[1]
        claims = validate_token(token)
        
        if not claims:
            return jsonify({"error": "Invalid token"}), 401
        
        request.claims = claims

@app.route('/health')
def health():
    return jsonify({"status": "healthy"})

@app.route('/<path:service_path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def forward_request(service_path):
    if not hasattr(request, 'claims'):
        return jsonify({"error": "Authentication required"}), 401
    
    backend_url = f"http://backend-service:8080/{service_path}"
    
    headers = {}
    for key, value in request.headers:
        if key.lower() not in ['authorization', 'host']:
            headers[key] = value
    
    if request.claims:
        headers['X-User-ID'] = str(request.claims.get('user_id', ''))
        headers['X-User-Roles'] = ','.join(request.claims.get('roles', []))
    
    try:
        response = requests.request(
            method=request.method,
            url=backend_url,
            headers=headers,
            data=request.get_data(),
            params=request.args,
            timeout=30
        )
        
        return response.content, response.status_code, response.headers.items()
    
    except Exception as e:
        return jsonify({"error": "Backend service error"}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8000)